package main

import (
	"fmt"
	"math/rand"
	"sync"
	"time"
)

// Bank represents a bank with multiple accounts
type Bank struct {
	accounts map[string]float64
	mu       sync.Mutex
}

// NewBank creates and returns a new Bank instance
func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]float64),
	}
}

// Deposit adds an amount to an account
func (b *Bank) Deposit(accountID string, amount float64) error {
	if amount <= 0 {
		return fmt.Errorf("deposit amount must be positive")
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	b.accounts[accountID] += amount
	return nil
}

// Withdraw removes an amount from an account if sufficient funds are available
func (b *Bank) Withdraw(accountID string, amount float64) error {
	if amount <= 0 {
		return fmt.Errorf("withdrawal amount must be positive")
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	if balance, exists := b.accounts[accountID]; !exists || balance < amount {
		return fmt.Errorf("insufficient funds or account not found for %s", accountID)
	}

	b.accounts[accountID] -= amount
	return nil
}

// GetBalance returns the current balance of an account
func (b *Bank) GetBalance(accountID string) float64 {
	b.mu.Lock()
	defer b.mu.Unlock()

	return b.accounts[accountID]
}

// ProcessTransaction simulates a series of transactions (deposits or withdrawals)
// on a random account by a single goroutine.
func ProcessTransaction(bank *Bank, accountIDs []string, wg *sync.WaitGroup, goroutineID int) {
	defer wg.Done()

	numTransactions := 10 // Each goroutine performs 10 transactions
	for i := 0; i < numTransactions; i++ {
		accountID := accountIDs[rand.Intn(len(accountIDs))]
		amount := float64(rand.Intn(100) + 1) // Amount between 1 and 100

		// Randomly choose between deposit and withdrawal
		if rand.Intn(2) == 0 { // 0 for deposit
			bank.Deposit(accountID, amount)
		} else { // 1 for withdrawal
			bank.Withdraw(accountID, amount)
		}
		time.Sleep(time.Duration(rand.Intn(50)) * time.Millisecond) // Simulate some work
	}
}

func main() {
	rand.Seed(time.Now().UnixNano())

	bank := NewBank()

	accountIDs := []string{"acc001", "acc002", "acc003", "acc004", "acc005"}
	initialBalance := 1000.0

	for _, id := range accountIDs {
		bank.Deposit(id, initialBalance)
		fmt.Printf("Initial balance for %s: %.2f\n", id, bank.GetBalance(id))
	}

	fmt.Println("----------------------------------------")
	fmt.Println("Starting concurrent transactions...")

	var wg sync.WaitGroup
	numGoroutines := 50
	for i := 0; i < numGoroutines; i++ {
		wg.Add(1)
		go ProcessTransaction(bank, accountIDs, &wg, i)
	}

	wg.Wait()

	fmt.Println("----------------------------------------")
	fmt.Println("All transactions completed.")

	totalFinalBalance := 0.0
	for _, id := range accountIDs {
		balance := bank.GetBalance(id)
		fmt.Printf("Final balance for %s: %.2f\n", id, balance)
		totalFinalBalance += balance
	}

	totalInitialBalance := float64(len(accountIDs)) * initialBalance
	fmt.Printf("Total initial balance: %.2f\n", totalInitialBalance)
	fmt.Printf("Total final balance: %.2f\n", totalFinalBalance)
}